scwin.f_Excel = async function(){

       //var objGridName = eval("gr_total");     
    let ret = await $c.win.confirm("Excel로 다운로드 하시겠습니까?");
    if (ret) {

    let colCount = 0;
    var nonColArray = new Array();
    for(let i = 0; i < gr_OnOffHireLduld.getTotalCol(); i++){
        if(gr_OnOffHireLduld.getColumnVisible(i)==true){
            colCount++;
        } 
    }


      let infoArr = [{
        rowIndex : 0, 
        colIndex : 0, 
        rowSpan : 1, 
        colSpan : colCount, 
        text : "On Hire 상하차 내역", 
        textAlign : "center",
        fontSize : 12,
        drawBorder:false,
        color : "black",
        backgroundColor : "#ffffff"
         },{
        rowIndex : 2, 
        colIndex : 0, 
        rowSpan : 1,
        colSpan : colCount, 
        text : "운송사 | "+ed_srchSelfTransCoNm.getValue()+"]"+" | 오더 No |"+ ed_odrNo.getValue() +" | 컨테이너"+ " | " +ed_cntrNo.getValue(), 
        textAlign : "left",
        fontSize : 10,
        drawBorder:false,
        color : "black",
        backgroundColor : "#ffffff"
        }]

    const options = {
        fileName: "On Hire 상하차 내역.xlsx",    // + ".xls",
        sheetName: "On Hire 상하차 내역",
        useStyle: true,     
        oddRowBackgroundColor: "#CCFFCC",
        startRowIndex : 3,
        startColumnIndex : 0,
        };
        await $c.data.downloadGridViewExcel(gr_OnOffHireLduld, options, infoArr);
    }
}
//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function(){

    let rtn = await $c.gus.cfValidate([ed_odrNo]);
	if(!rtn){
		return false;
	}
    dma_condition.set("odrNo", ed_odrNo.getValue());
    dma_condition.set("cntrNo", ed_cntrNo.getValue());
    dma_condition.set("odrCompleteYn", acb_odrCompleteYn.getValue());
	$c.sbm.execute(sbm_retrieve);
}; 

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function(){
	if (ds_onOffHireLduld.getModifiedIndex().length == 0) {
		$c.gus.cfAlertMsg(MSG_CM_ERR_001,["On Hire 상하차 내역"]); // "@은(는) 변경된 사항이 없습니다."
  		return;
	}

	if(ed_srchSelfTransCoCd.getValue() == ""){
		$c.gus.cfAlertMsg(MSG_CM_ERR_002,["자가운송사"]);
		ed_srchSelfTransCoCd.focus();
		return;
	}

	// 검색조건 필수 입력 체크
  	if (!$c.gus.cfValidate([gr_OnOffHireLduld])) {
  		return;
	}

	for (var i=0; i<= ds_onOffHireLduld.getRowCount(); i++) {
		if(ds_onOffHireLduld.getCellData(i,"crryinoutIntendDt") != scwin.nowDt){
			if(ds_onOffHireLduld.getCellData(i,"wrkPlCd") == "4C02") {
				$c.win.alert("금일 신규 예약 하십시오.");
				return;
			}

		}
		if (ds_onOffHireLduld.getRowStatus(i) == "U") {
			if (ds_onOffHireLduld.getCellData(i,"crryinoutIntendHh").length != 4) {
				$c.gus.cfAlertMsg(MSG_CM_ERR_055, ["시간형식"]);
				ds_onOffHireLduld.setRowPosition(i);
				gr_OnOffHireLduld.setFocusedCell(i, 5); //SetColumn("crryinoutIntendHh");
				//gr_OnOffHireLduld.focus();
			    return false;
			}
			if (ds_onOffHireLduld.getCellData(i,"crryinoutIntendHh").substr(0,2) > "23") {
				$c.gus.cfAlertMsg(MSG_CM_ERR_021,["반납예정시간"]); // "@은(는) 시가 잘못되었습니다."
				ds_onOffHireLduld.setRowPosition(i);
				gr_OnOffHireLduld.setFocusedCell(i, 5);
				gr_OnOffHireLduld.focus();
			    return false;
			}
			if (ds_onOffHireLduld.getCellData(i,"crryinoutIntendHh").substr(2,2) > "59") {
				$c.gus.cfAlertMsg(MSG_CM_ERR_022,["반납예정시간"]); // "@은(는) 분이 잘못되었습니다."
				ds_onOffHireLduld.setRowPosition(i);
				gr_OnOffHireLduld.setFocusedCell(i, 5);
				gr_OnOffHireLduld.focus();
			    return false;
			}

			if (ds_onOffHireLduld.getCellData(i,"crryinoutIntendNo") == "") {
				ds_onOffHireLduld.setCellData(i,"selfTransCoClntNo", ed_srchSelfTransCoCd.getValue());
			}
		}
	}
	var strOdrNo = ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "odrNo");
	if(ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "TSL" && strOdrNo.substring(1,3)== "C5"){	
   	   	   alert("TSL라인 수입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
   	       return false;
    }else if(ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "EAS" && strOdrNo.substring(1,3)== "C5"){  
   	   	   alert("EAS라인 수입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
   	       return false;
   	}else if(ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "APL"){  
   	   	   alert("APL라인 수출입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
   	       return false;
   	}else if(ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "COH" && strOdrNo.substring(1,3)== "C5" && $s.gus.cfIsNull(ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "bookingNo"))){  
   	   	   if(scwin.loginId == "010028"){
                let rtn = await $c.win.confirm("저장 하시겠습니까?");
	  		   	if(rtn){
					//tr_regist.Post();
				} 
	  	   }else{
	  	   		$c.win.alert("COH라인 수입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
	  	   		return false;
	  	   }
   	}else if(ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "YNK" ){  
   	   	  if(scwin.loginId == "010028"){
	  		   	if($c.gus.cfConfirmMsg("저장 하시겠습니까?")){
					//tr_regist.Post();
				} 
	  	   }else{
	  	   		$c.win.alert("YNK라인 수입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
	  	   		return false;
	  	   }  	       
   	}else if(ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "SITC" ){  
   	   	   if(scwin.loginId == "072893" || scwin.loginId == "073294" || scwin.loginId == "281776" || scwin.loginId == "010028"){
   		   		if($c.gus.cfConfirmMsg("저장 하시겠습니까?")){
					//tr_regist.Post();
				} 
   		   }
   		   else{
	   	   	   $c.win.alert("SITC라인 수출입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
	   	       return false;          
	   	   }
   	}else if(ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "NOLS" 
   			|| ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "TCLC" 
   			|| ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "SOFC" 
   			|| ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "TMSC"
   			|| ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "TJM"
   			|| ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "MAS"
   			|| ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "JJS"
   			|| ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "DWH"
   			|| ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "RHT"
   			|| ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "ONE"   			
   			){  
   		   //두우해운 문상보 대리 요청..	, 2014.09.22 TMSC라인 추가
   		   if(scwin.loginId == "040300" || scwin.loginId == "001234"){
   		   		if($c.gus.cfConfirmMsg("저장 하시겠습니까?")){
					//tr_regist.Post();
				} 
   		   }
   		   else{
	   	   	   $c.win.alert("NOLS, TCLC, SOFC, TMSC, TJM, MAS, JJS, DWH, RHT, ONE 라인 수출입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
	   	       return false;         
	   	   }
   	}else if(ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "COS" ){  
		$c.win.alert("COS라인 수출입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
		return false;          
   	}else if(ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "MOL" ){  
		$c.win.alert("MOL라인 수출입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
		return false;          
   	}else if( await $c.win.confirm("저장 하시겠습니까?")){

		 $c.sbm.execute(sbm_save); 
	}
};

scwin.sbm_save_submitDone = async function(){
    await $c.gus.cfAlertMsg(MSG_CM_INF_001);	// 성공적으로 저장하였습니다
    scwin.f_Retrieve();

}

scwin.f_crryInOutEDI = async function(bAlertFlag, bSaveFlag, bTransferFlag, row, bDeleteFlag){

	//현재시간 세팅


    currTime = WebSquare.date.getCurrentServerDate("hh:mm");
	if(currTime > "1730" && (ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(),"wrkPlCd") == "6C01")){ //&& currDay == "0" && currDay == "6"){
		$c.win.alert("17시 30분 이후에는 KBCTCY의 요청으로 EDI 전송을 할 수 없습니다.");
		return false;
	}
	//임시공휴일
	/*
	if("20161005" == tempHoliday
		&& ds_onOffHireLduld.NameValue(ds_onOffHireLduld.Rowposition,"wrkPlCd") == "6C01"){
		alert("KBCTCY의 요청으로 EDI 전송을 할 수 없습니다.");
		return false;
	}
	*/		

	if (ds_onOffHireLduld.getRowCount() == 0) {
		return;
	}



	var strOdrNo = ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "odrNo");

	if(ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "TSL" && strOdrNo.substring(1,3)== "C5"){	
   	   	   $c.win.alert("TSL라인 수입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
   	       return false;
    }else if(ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "EAS" && strOdrNo.substring(1,3)== "C5"){  
   	   	   $c.win.alert("EAS라인 수입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
   	       return false;
   	}else if(ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "APL"){  
   	   	   $c.win.alert("APL라인 수출입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
   	       return false;
   	}else if(ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "COH" && strOdrNo.substring(1,3)== "C5" && $c.gus.cfIsNull(ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "bookingNo"))){  
   	   	   $c.win.alert("COH라인 수입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
   	       return false;
   	}else if(ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "YNK" && strOdrNo.substring(1,3)== "C5"){  
   	   	   $c.win.alert("YNK라인 수입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
   	       return false;   	      
   	}else if(ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "LGL" 
   			&& strOdrNo.substring(1,3)== "C5" &&	(ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(),"fullEmptyClsCd") == "F") 
   			&& $c.gus.cfIsNull(ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "bookingNo"))){
   		   $c.win.alert("부킹번호가 없습니다. LGL라인 담당자를 통하여 처리하세요!!!");
	       return false;
   	}else if(ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "SITC" ){  
   	   	   if(scwin.loginId == "072893" || scwin.loginId == "073294" || scwin.loginId == "281776" || scwin.loginId == "010028" ){
   		   		if($c.gus.cfConfirmMsg("저장 하시겠습니까?")){
					//tr_regist.Post();
				} 
   		   }
   		   else{
	   	   	   $c.win.alert("SITC라인 수출입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
	   	       return false;          
