/*현재시간조회 0000 현태로 가져온다.*/
scwin.f_getTime = function(){
    currDate = new Date();
    //currDate = new Date(2015, 1, 16, 16, 1, 1);
    currTime = scwin.leadingZeros(currDate.getHours(),2)+scwin.leadingZeros(currDate.getMinutes(),2);
    currDay = currDate.getDay();
    tempHoliday = currDate.getYear() + scwin.leadingZeros(currDate.getMonth()+1,2) + scwin.leadingZeros(currDate.getDate(),2);
}

/**
 * 자릿수 앞자리 0 채우기
 * leadingZeros([num], [자릿수]) 
 * > leadingZeros(12, 3) -> '012'
 */
scwin.leadingZeros = function(n, digits) {
    var zero = '';
    n = n.toString();
    if (n.length < digits) {
        for (i = 0; i < digits - n.length; i++) {
            zero += '0';
        }
    }
    return zero + n;
}

