	var odrDelYn      = ""; //오더삭제여부
	var odrCompleteYn = ""; //오더완료여부
	var odrCompleteDt = ""; //완료일자
    if(ds_onOffHireLduld.getRowCount() == 0 ){
        $c.gus.cfAlertMsg(MSG_CM_ERR_003);
//		cfDisableObjects([btn_01,btn_02,btn_03]);
		$c.gus.cfDisableObjects([btn_03]);
		$c.gus.cfDisableObjects([btn_04]);

		odrNo         = ""; //오더번호
		lineNm        = ""; //LINE명
		regiNm        = ""; //담당자
		odrDelYn      = ""; //오더삭제여부
		odrCompleteYn = ""; //오더완료여부
		odrCompleteDt = ""; //완료일자
    } else {
//  		cfEnableObjects([btn_01,btn_02,btn_03]);
  		//cfEnableObjects([btn_03]);

		$c.gus.cfEnableObj(btn_03,true);
		$c.gus.cfEnableObj(btn_04,true);

		odrNo         = ds_onOffHireLduld.getCellData(0, "odrNo");
