			odrCompleteDt = $c.gus.cfGetFormatStr(ds_onOffHireLduld.getCellData(0, "odrCompleteDt"), "####/##/##");
		}
	};

    ed_odrNo1.setValue(odrNo);
	ed_lineNm.setValue(lineNm);
	ed_regiNm.setValue(regiNm);
	ed_odrDelYn.setValue(odrDelYn);
	ed_odrCompleteYn.setValue(odrCompleteYn);
	ed_odrCompleteDt.setValue(odrCompleteDt);

	var userClsCd = scwin.userClsCd;

